<template>
  <div class="main">
    <div class="logo">
      <img src="@/assets/img/logo.jpg" alt="" />
    </div>
    <div class="menu flex-direction-column">
      <div
        class="item flex-direction-column"
        v-for="item in menu"
        :key="item.name"
        :class="item.route === nowPath && 'active'"
        @click="itemClick(item)"
      >
        <div class="flex">
          <img :src="item.icon" mode="scaleToFill" />
          <span>{{ item.name }}</span>
          <el-icon v-if="item.children?.length && !isShow">
            <ArrowRight />
          </el-icon>
          <el-icon v-if="item.children?.length && isShow">
            <ArrowDown />
          </el-icon>
        </div>
        <view
          v-if="item.children?.length && isShow"
          class="drop flex-direction-column"
          @click.stop
        >
          <view
            class="drop-item"
            v-for="ii in item.children"
            :key="ii.name"
            :class="ii.route === nowPath && 'active'"
            @click.stop="itemClick(ii)"
          >
            {{ ii.name }}
          </view>
        </view>
      </div>
    </div>
  </div>
</template>

<script setup>
import { ref, watch } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { ArrowRight, ArrowDown } from '@element-plus/icons-vue'

import menu_version from '@/assets/img/menu/menu_version.png'
import menu_topic from '@/assets/img/menu/menu_topic.png'
import menu_devices from '@/assets/img/menu/menu_devices.png'
import menu_status from '@/assets/img/menu/menu_status.png'
import menu_log from '@/assets/img/menu/menu_log.png'
import menu_config from '@/assets/img/menu/menu_config.png'
import menu_alarm from '@/assets/img/menu/menu_alarm.png'

const route = useRoute()
const router = useRouter()

const nowPath = ref('')

const isShow = ref(false)

const menu = ref([
  {
    name: '机器人状态',
    icon: menu_status,
    route: '/status'
  },
  {
    name: '设备',
    icon: menu_devices,
    route: '/devices',
    children: [
      {
        name: '关节',
        route: '/devices/joint'
      },
      {
        name: 'IMU',
        route: '/devices/imu'
      },
      {
        name: '电源',
        route: '/devices/power'
      },
      {
        name: '电池',
        route: '/devices/battery'
      },
      {
        name: '遥控',
        route: '/devices/remote'
      },
      {
        name: '声卡',
        route: '/devices/audio'
      }
    ]
  },
  {
    name: '报警',
    icon: menu_alarm,
    route: '/alarm'
  },
  {
    name: 'Topic',
    icon: menu_topic,
    route: '/topic'
  },
  {
    name: '配置',
    icon: menu_config,
    route: '/config'
  },
  {
    name: '版本',
    icon: menu_version,
    route: '/version'
  },
  {
    name: '日志',
    icon: menu_log,
    route: '/log'
  }
])

const itemClick = (item) => {
  if (item.children?.length) {
    // 先展开/折叠子菜单
    isShow.value = !isShow.value
    // 同时导航到主菜单的路由devices
    if (item.route) {
      router.push(item.route)
    }
  } else if (item.route) {
    // 如果是子菜单，直接导航
    router.push(item.route)
  }
}

watch(
  () => route.path,
  async (val) => {
    nowPath.value = val
  },
  {
    immediate: true,
    deep: true
  }
)
</script>

