      object-fit: contain; // 改为 contain
    }
  }
  .menu {
    border-top: 1px solid #eee;
    width: 100%;
    margin-top: 15px;
    align-items: center;
    justify-content: center;
    .item {
      margin-top: 20px;
      width: 90%;
      padding: 5px 10px;
      border-radius: 5px;
      cursor: pointer;
      img {
        width: 15px;
        height: 15px;
        object-fit: contain;
      }
      span {
        font-size: 18px;
        display: block;
        flex: 1;
